(()=>{document.addEventListener("DOMContentLoaded",()=>{let t=document.querySelectorAll('.toggle-switch input[type="checkbox"]');t.forEach(e=>{e.setAttribute("role","switch"),e.setAttribute("aria-checked",e.checked)}),t.forEach(e=>{e.addEventListener("change",()=>{e.setAttribute("aria-checked",e.checked),e.dispatchEvent(new CustomEvent("toggle:changed",{detail:{checked:e.checked,name:e.name,value:e.value},bubbles:!0}))}),e.addEventListener("keydown",c=>{(c.key===" "||c.keyCode===32)&&(c.preventDefault(),e.checked=!e.checked,e.dispatchEvent(new Event("change",{bubbles:!0})))})})});})();
